#include "SYsULexer.h" // 确保这里的头文件名与您生成的词法分析器匹配
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <string>
#include <vector>
#include <sstream>

// 全局变量跟踪预处理信息
static std::string currentFileName = "";
static int currentLine = 1;
static int lineOffset = 0;

// 映射定义，将ANTLR的tokenTypeName映射到clang的格式
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  // Keywords
  { "Int", "int" },
  { "Return", "return" },
  { "While", "while" },
  { "If", "if" },
  { "Else", "else" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Const", "const" },
  { "Void", "void" },

  // Identifiers and constants
  { "Identifier", "identifier" },
  { "Constant", "numeric_constant" },

  // Punctuators
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "LeftBrace", "l_brace" },
  { "RightBrace", "r_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Semi", "semi" },
  { "Comma", "comma" },

  // Operators
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Less", "less" },
  { "LessEqual", "lessequal" },
  { "Greater", "greater" },
  { "GreaterEqual", "greaterequal" },
  { "Equal", "equal" },
  { "EqualEqual", "equalequal" },
  { "Exclaim", "exclaim" },
  { "ExclaimEqual", "exclaimequal" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },

  // Special
  { "EOF", "eof" },
  { "LineAfterPreprocessing", "line_marker" }
};

// 解析预处理行标记，更新当前文件名和行号
void process_line_marker(const std::string& marker) {
  std::istringstream iss(marker);
  char hash;
  iss >> hash; // 读取 '#'

  int lineNum;
  iss >> lineNum;

  std::string filename;
  char quote;
  iss >> quote; // 读取第一个引号
  if (quote == '"') {
    std::getline(iss, filename, '"'); // 读取到下一个引号
  }

  // 更新当前行号和文件名
  if (!filename.empty()) {
    currentFileName = filename;
    lineOffset = lineNum - 1; // 行号偏移
  }
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  // 处理预处理行标记
  if (tokenTypeName == "LineAfterPreprocessing") {
    process_line_marker(token->getText());
    return; // 不输出预处理标记
  }

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 计算位置信息
  int line = token->getLine();
  int column = token->getCharPositionInLine() + 1; // ANTLR 从0开始，clang从1开始

  // 调整行号：考虑预处理行标记的偏移
  int adjustedLine = line + lineOffset;

  std::string locInfo;
  if (tokenTypeName == "eof") {
    // EOF 的特殊处理：行号+1，列号1
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine + 1) + ":1>";
  } else {
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine) + ":" + std::to_string(column) + ">";
  }

  // 判断 StartOfLine 和 LeadingSpace
  bool startOfLine = (column == 1);
  bool leadingSpace = (column > 1); // 简化处理：如果列号>1，则认为前面有空格

  // 输出 token
  outFile << tokenTypeName << " '" << (token->getText() == "<EOF>" ? "" : token->getText()) << "'";

  // 输出标记
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << "\t [LeadingSpace]";

  // 输出位置信息
  outFile << "\t" << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }
}

